   102→/**
   103→ * Base class wrapper for both stream encoder and decoder filters.
   104→ *
   105→ * This class is responsible for performing matching and updating match data when a match tree is
   106→ * configured for the associated filter. When not using a match tree, only minimal overhead (i.e.
   107→ * memory overhead of unused fields) should apply.
   108→ */
   109→struct ActiveStreamFilterBase : public virtual StreamFilterCallbacks,
   110→                                Logger::Loggable<Logger::Id::http> {
   111→  ActiveStreamFilterBase(FilterManager& parent, FilterContext filter_context)
   112→      : parent_(parent), iteration_state_(IterationState::Continue),
   113→        filter_context_(std::move(filter_context)) {}
   114→
   115→  // Functions in the following block are called after the filter finishes processing
   116→  // corresponding data. Those functions handle state updates and data storage (if needed)
   117→  // according to the status returned by filter's callback functions.
   118→  bool commonHandleAfter1xxHeadersCallback(Filter1xxHeadersStatus status);
   119→  bool commonHandleAfterHeadersCallback(FilterHeadersStatus status, bool& end_stream);
   120→  bool commonHandleAfterDataCallback(FilterDataStatus status, Buffer::Instance& provided_data,
   121→                                     bool& buffer_was_streaming);
   122→  bool commonHandleAfterTrailersCallback(FilterTrailersStatus status);
   123→
   124→  // Buffers provided_data.
   125→  void commonHandleBufferData(Buffer::Instance& provided_data);
   126→
   127→  // If iteration has stopped for all frame types, calls this function to buffer the data before
   128→  // the filter processes data. The function also updates streaming state.
   129→  void commonBufferDataIfStopAll(Buffer::Instance& provided_data, bool& buffer_was_streaming);
   130→
   131→  void commonContinue();
