   133→  virtual Buffer::InstancePtr createBuffer() PURE;
   134→  virtual Buffer::InstancePtr& bufferedData() PURE;
   135→  virtual bool observedEndStream() PURE;
   136→  virtual bool has1xxHeaders() PURE;
   137→  virtual void do1xxHeaders() PURE;
