   161→  void resetIdleTimer() override;
   162→  const Router::RouteSpecificFilterConfig* mostSpecificPerFilterConfig() const override;
   163→  Router::RouteSpecificFilterConfigs perFilterConfigs() const override;
   164→  Http1StreamEncoderOptionsOptRef http1StreamEncoderOptions() override;
   165→  OptRef<DownstreamStreamFilterCallbacks> downstreamCallbacks() override;
   166→  OptRef<UpstreamStreamFilterCallbacks> upstreamCallbacks() override;
   167→  absl::string_view filterConfigName() const override { return filter_context_.config_name; }
   168→  RequestHeaderMapOptRef requestHeaders() override;
   169→  RequestTrailerMapOptRef requestTrailers() override;
   170→  ResponseHeaderMapOptRef informationalHeaders() override;
   171→  ResponseHeaderMapOptRef responseHeaders() override;
   172→  ResponseTrailerMapOptRef responseTrailers() override;
   173→
   174→  // Functions to set or get iteration state.
   175→  bool canIterate() { return iteration_state_ == IterationState::Continue; }
   176→  bool stoppedAll() {
   177→    return iteration_state_ == IterationState::StopAllBuffer ||
   178→           iteration_state_ == IterationState::StopAllWatermark;
   179→  }
   180→  void allowIteration() {
   181→    ASSERT(iteration_state_ != IterationState::Continue);
